 24→/**
 25→ * 員工年度假別額度清單查詢 Processor
 26→ * <p>
 27→ * 提供員工年度假別額度列表查詢功能，支援複合條件篩選與分頁。
 28→ * API 路徑：POST /api/empVacationQuery
 29→ * <p>
 30→ * 查詢條件（皆為選填）：
 31→ * - year:    年度（Integer，精準比對，前端預設帶入當前年度）
 32→ * - orgName: 部門名稱（String，模糊比對）
 33→ * - keyword: 員工編號或姓名（String，模糊比對）
 34→ * <p>
 35→ * 回應欄位（data.records 陣列，每筆）：
 36→ * - empId:      員工 ID（前端跳轉明細時使用）
 37→ * - empAccount: 員工編號
 38→ * - empName:    員工姓名
 39→ * - orgName:    部門名稱
 40→ *
 41→ * @author SoeTek Team
 42→ * @since 2026-03-18
 43→ */
 44→@Slf4j
 45→@ApplicationScoped
 46→@Named("empVacationQueryProcessor")
 47→@RegisterForReflection
 48→public class EmpVacationQueryProcessor extends ApiRouteProcessor {
 49→
 50→    @Inject
 51→    EmpVacationQueryService empVacationQueryService;
 52→
 53→    @Override
 54→    public Map<String, Object> getTemplateParams() {
 55→        return Map.of(
 56→                "routeId", "empVacationQuery",
 57→                "apiDescription", "查詢員工年度假別額度清單",
 58→                "requiredFields", ""
 59→        );
 60→    }
 61→
 62→    @Override
 63→    protected String getProcessorType() {
 64→        return LogType.API_PROCESSING;
 65→    }
 66→
 67→    @Override
 68→    @ActivateRequestContext
 69→    @AuditLog(
 70→            operation = AuditLog.OperationType.QUERY,
 71→            entity = "TmEmpVacation",
 72→            description = "查詢員工年度假別額度清單",
 73→            logParameters = true,
 74→            logResult = true
 75→    )
 76→    public Object process(Exchange exchange, @Body Map<String, Object> payload,
 77→                          @Headers Map<String, Object> headers) throws Exception {
 78→        return executeWithErrorHandling(exchange, payload, headers);
 79→    }
 80→
 81→    @Override
 82→    protected Object processBusinessLogic(
 83→            Exchange exchange,
 84→            Map<String, Object> payload,
 85→            Map<String, Object> headers,
 86→            String traceId,
 87→            String routeId) throws Exception {
 88→
 89→        log.debug("[員工假別清單查詢] 開始 - TraceId: {}, Payload: {}", traceId, payload);
 90→
 91→        // 1. 解析分頁參數
 92→        PaginationParams paginationParams = PaginationUtil.parsePaginationParams(payload);
 93→
 94→        // 2. 呼叫 Service 執行跨表查詢
 95→        List<Map<String, Object>> records = empVacationQueryService.queryEmpVacationList(payload);
 96→
 97→        log.debug("[員工假別清單查詢] 查詢完成 - 總筆數: {}, TraceId: {}", records.size(), traceId);
 98→
 99→        // 3. 執行記憶體分頁
100→        PaginationResult<Map<String, Object>> result = PaginationUtil.paginate(records, paginationParams);
101→
102→        log.info("[員工假別清單查詢] 成功 - TotalCount: {}, CurrentPage: {}, PerPage: {}, TraceId: {}",
103→                result.getTotalCount(), result.getCurrentPage(), paginationParams.getPerPage(), traceId);
104→
105→        // 4. 組裝標準回應
106→        Map<String, Object> response = new HashMap<>(result.toResponseMap("查詢成功"));
107→        response.put("traceId", traceId);
108→
109→        // 5. 重新命名 items → records（符合前端慣例）
110→        @SuppressWarnings("unchecked")
111→        Map<String, Object> data = (Map<String, Object>) response.get("data");
112→        if (data != null && data.containsKey("items")) {
113→            Map<String, Object> enhancedData = new HashMap<>(data);
114→            enhancedData.put("records", enhancedData.remove("items"));
115→            response.put("data", enhancedData);
116→        }
117→
118→        return response;
119→    }
120→}
