 20→/**
 21→ * 依員工編號查詢員工基本資訊 Processor
 22→ * <p>
 23→ * 前端輸入工號後呼叫，回傳員工基本資訊供頁面帶入
 24→ * <p>
 25→ * 必填：empAccount（員工編號）
 26→ * API 路徑：POST /api/tmEmpInfoQuery
 27→ *
 28→ * @author SoeTek Team
 29→ * @since 2026-03-17
 30→ */
 31→@Slf4j
 32→@ApplicationScoped
 33→@Named("tmEmpInfoQueryProcessor")
 34→@RegisterForReflection
 35→public class TmEmpInfoQueryProcessor extends ApiRouteProcessor {
 36→
 37→    @Inject
 38→    TmEmployeeQueryService empQueryService;
 39→
 40→    @Override
 41→    public Map<String, Object> getTemplateParams() {
 42→        return Map.of(
 43→                "routeId", "tmEmpInfoQuery",
 44→                "apiDescription", "依員工編號查詢員工基本資訊",
 45→                "requiredFields", "empAccount");
 46→    }
 47→
 48→    @Override
 49→    protected String getProcessorType() {
 50→        return LogType.API_PROCESSING;
 51→    }
 52→
 53→    @Override
 54→    @ActivateRequestContext
 55→    @AuditLog(
 56→            operation = AuditLog.OperationType.QUERY,
 57→            entity = "PmEmployee",
 58→            description = "依員工編號查詢員工基本資訊",
 59→            logParameters = true,
 60→            logResult = true
 61→    )
 62→    public Object process(Exchange exchange, @Body Map<String, Object> payload,
 63→                          @Headers Map<String, Object> headers) throws Exception {
 64→        return executeWithErrorHandling(exchange, payload, headers);
 65→    }
 66→
 67→    @Override
 68→    protected Object processBusinessLogic(
 69→            Exchange exchange,
 70→            Map<String, Object> payload,
 71→            Map<String, Object> headers,
 72→            String traceId,
 73→            String routeId) throws Exception {
 74→
 75→        // 取得員工編號
 76→        Object accountObj = payload.get("empAccount");
 77→        if (accountObj == null || accountObj.toString().trim().isEmpty()) {
 78→            throw new IllegalArgumentException("empAccount 為必填參數");
 79→        }
 80→        String empAccount = accountObj.toString().trim();
 81→
 82→        log.debug("[員工查詢] empAccount: {}, TraceId: {}", empAccount, traceId);
 83→
 84→        Map<String, Object> empInfo = empQueryService.getEmployeeByAccount(empAccount);
 85→
 86→        if (empInfo == null) {
 87→            Map<String, Object> response = new HashMap<>();
 88→            response.put("success", false);
 89→            response.put("code", "NOT_FOUND");
 90→            response.put("message", "查無此員工：" + empAccount);
 91→            response.put("traceId", traceId);
 92→            return response;
 93→        }
 94→
 95→        log.info("[員工查詢] 查詢成功 - empAccount: {}, TraceId: {}", empAccount, traceId);
 96→
 97→        Map<String, Object> response = new HashMap<>();
 98→        response.put("success", true);
 99→        response.put("message", "查詢成功");
100→        response.put("data", empInfo);
101→        response.put("traceId", traceId);
102→        return response;
103→    }
104→}
