139→    // ==================== Panache 查詢方法 ====================
140→
141→    /**
142→     * 查詢假別明細列表（支援複合條件篩選）
143→     * <p>
144→     * 回傳所有明細記錄，包含：
145→     * - 同一假別代碼的不同生效日期版本
146→     * - 啟用細項分類時的各個細項記錄
147→     * <p>
148→     * 支援的查詢條件：
149→     * - vacationCodeFrom: 假別代碼起
150→     * - vacationCodeTo: 假別代碼訖
151→     * - keyword: 關鍵字（模糊比對代碼、名稱、日期）
152→     * - isEffective: 是否有效
153→     * - payRatePercent: 計薪比例
154→     * - sortBy: 排序欄位
155→     * - sortOrder: 排序方向 (asc/desc)
156→     *
157→     * @param criteria 查詢條件 Map
158→     * @return 符合條件的假別明細列表
159→     */
160→    public static List<TmVacationDetailSettingEntity> findMainDetails(Map<String, Object> criteria) {
161→        // 查詢所有明細記錄（包含不同生效日期、不同細項）
162→        // 每一筆明細都會顯示在列表中
163→        StringBuilder query = new StringBuilder("FROM TmVacationDetailSettingEntity v WHERE 1=1");
164→        List<Object> params = new ArrayList<>();
165→
166→        // 假別代碼區間查詢
167→        if (criteria.containsKey("vacationCodeFrom") && criteria.get("vacationCodeFrom") != null) {
168→            String codeFrom = criteria.get("vacationCodeFrom").toString().trim();
169→            if (!codeFrom.isEmpty()) {
170→                query.append(" AND v.vacationCode >= ?").append(params.size() + 1);
171→                params.add(codeFrom);
172→            }
173→        }
174→        if (criteria.containsKey("vacationCodeTo") && criteria.get("vacationCodeTo") != null) {
175→            String codeTo = criteria.get("vacationCodeTo").toString().trim();
176→            if (!codeTo.isEmpty()) {
177→                query.append(" AND v.vacationCode <= ?").append(params.size() + 1);
178→                params.add(codeTo);
179→            }
180→        }
181→
182→        // 關鍵字模糊查詢（代碼、名稱、日期）
183→        if (criteria.containsKey("keyword") && criteria.get("keyword") != null) {
184→            String keyword = criteria.get("keyword").toString().trim();
185→            if (!keyword.isEmpty()) {
186→                String likeKeyword = "%" + keyword + "%";
187→                query.append(" AND (v.vacationCode LIKE ?").append(params.size() + 1);
188→                params.add(likeKeyword);
189→                // 假別名稱（從主檔查詢）
190→                query.append(" OR EXISTS (SELECT 1 FROM TmVacationSettingEntity m WHERE m.vacationCode = v.vacationCode AND m.vacationName LIKE ?").append(params.size() + 1).append(")");
191→                params.add(likeKeyword);
192→                query.append(" OR CAST(v.beginDate AS string) LIKE ?").append(params.size() + 1);
193→                params.add(likeKeyword);
194→                query.append(" OR CAST(v.endDate AS string) LIKE ?").append(params.size() + 1);
195→                params.add(likeKeyword);
196→                query.append(")");
197→            }
198→        }
199→
200→        // 是否有效篩選
201→        if (criteria.containsKey("isEffective") && criteria.get("isEffective") != null) {
202→            Object isEffectiveValue = criteria.get("isEffective");
203→            Boolean isEffective = null;
204→            if (isEffectiveValue instanceof Boolean) {
205→                isEffective = (Boolean) isEffectiveValue;
206→            } else if (isEffectiveValue instanceof String) {
207→                String strValue = ((String) isEffectiveValue).trim();
208→                if (!strValue.isEmpty()) {
209→                    isEffective = Boolean.parseBoolean(strValue);
210→                }
211→            }
212→            if (isEffective != null) {
213→                query.append(" AND v.isEffective = ?").append(params.size() + 1);
214→                params.add(isEffective);
215→            }
216→        }
217→
218→        // 計薪比例篩選（注意：0 也是有效值，代表無薪）
219→        if (criteria.containsKey("payRatePercent") && criteria.get("payRatePercent") != null) {
220→            Object payRateValue = criteria.get("payRatePercent");
221→            Integer payRatePercent = null;
222→            if (payRateValue instanceof Number) {
223→                payRatePercent = ((Number) payRateValue).intValue();
224→            } else if (payRateValue instanceof String) {
225→                String strValue = ((String) payRateValue).trim();
226→                if (!strValue.isEmpty()) {
227→                    try {
228→                        payRatePercent = Integer.parseInt(strValue);
229→                    } catch (NumberFormatException e) {
230→                        // 忽略無效數值
231→                    }
232→                }
233→            }
234→            if (payRatePercent != null) {
235→                query.append(" AND v.payRatePercent = ?").append(params.size() + 1);
236→                params.add(payRatePercent);
237→            }
238→        }
239→
240→        // 動態排序
241→        String sortBy = criteria.get("sortBy") != null ? criteria.get("sortBy").toString().trim() : null;
242→        String sortOrder = criteria.get("sortOrder") != null ? criteria.get("sortOrder").toString().trim() : "asc";
243→
244→        // 欄位映射：前端欄位名稱 -> Entity 欄位
245→        String orderByColumn = "v.vacationCode"; // 預設排序欄位
246→        if (sortBy != null && !sortBy.isEmpty()) {
247→            orderByColumn = switch (sortBy) {
248→                case "vacationCode" -> "v.vacationCode";
249→                case "isEffective" -> "v.isEffective";
250→                case "payRatePercent" -> "v.payRatePercent";
251→                case "minHours" -> "v.minHours";
252→                case "maxHours" -> "v.maxHours";
253→                case "beginDate" -> "v.beginDate";
254→                case "endDate" -> "v.endDate";
255→                default -> "v.vacationCode";
256→            };
257→        }
258→
259→        // 排序方向（只允許 ASC 或 DESC，防止注入）
260→        String orderDirection = "desc".equalsIgnoreCase(sortOrder) ? "DESC" : "ASC";
261→        query.append(" ORDER BY ").append(orderByColumn).append(" ").append(orderDirection);
262→
263→        // 次要排序：假別代碼
264→        if (!"v.vacationCode".equals(orderByColumn)) {
265→            query.append(", v.vacationCode ASC");
266→        }
267→
268→        PanacheQuery<TmVacationDetailSettingEntity> panacheQuery = find(query.toString(), params.toArray());
269→        return panacheQuery.list();
270→    }
271→
272→    /**
273→     * 根據主鍵查詢
274→     *
275→     * @param vacationSubId 流水號
276→     * @return 假別明細
277→     */
278→    public static TmVacationDetailSettingEntity findByKey(Integer vacationSubId) {
279→        return find("vacationSubId", vacationSubId).firstResult();
280→    }
281→
282→    /**
283→     * 根據假別代碼查詢主設定（無細項）
284→     *
285→     * @param vacationCode 假別代碼
286→     * @return 假別主設定
287→     */
288→    public static TmVacationDetailSettingEntity findMainByCode(String vacationCode) {
289→        return find("vacationCode = ?1 AND vacationSubCode IS NULL AND isEffective = true ORDER BY beginDate DESC",
290→                vacationCode).firstResult();
291→    }
292→
293→    /**
294→     * 根據假別代碼查詢所有明細（含細項）
295→     *
296→     * @param vacationCode 假別代碼
297→     * @return 假別明細列表
298→     */
299→    public static List<TmVacationDetailSettingEntity> findByCode(String vacationCode) {
300→        return find("vacationCode = ?1 ORDER BY vacationSubCode, beginDate DESC", vacationCode).list();
301→    }
302→
303→    /**
304→     * 根據假別代碼和細項代碼查詢
305→     *
306→     * @param vacationCode    假別代碼
307→     * @param vacationSubCode 細項代碼
308→     * @return 假別細項設定
309→     */
310→    public static TmVacationDetailSettingEntity findByCodeAndSubCode(String vacationCode, String vacationSubCode) {
311→        return find("vacationCode = ?1 AND vacationSubCode = ?2 AND isEffective = true ORDER BY beginDate DESC",
312→                vacationCode, vacationSubCode).firstResult();
313→    }
314→
315→    /**
316→     * 查詢指定假別的所有細項（排除主設定）
317→     *
318→     * @param vacationCode 假別代碼
319→     * @return 細項列表
320→     */
321→    public static List<TmVacationDetailSettingEntity> findSubItems(String vacationCode) {
322→        return find("vacationCode = ?1 AND vacationSubCode IS NOT NULL AND isEffective = true ORDER BY vacationSubCode",
323→                vacationCode).list();
324→    }
325→
326→    /**
327→     * 刪除指定假別代碼的所有明細
328→     *
329→     * @param vacationCode 假別代碼
330→     * @return 刪除筆數
331→     */
332→    public static long deleteByVacationCode(String vacationCode) {
333→        return delete("vacationCode", vacationCode);
334→    }
335→}
