23→/**
24→ * {Entity 中文名稱} Entity
25→ */
26→@Data
27→@NoArgsConstructor
28→@AllArgsConstructor
29→@EqualsAndHashCode(callSuper = false)
30→@Entity
31→@Table(name = "{TABLE_NAME}")              // 不加 schema — Hibernate 自動處理
32→@RegisterForReflection
33→@Cacheable                                  // ⭐ 必加
34→@Cache(usage = CacheConcurrencyStrategy.READ_WRITE)  // ⭐ 必加
35→public class {EntityName}Entity extends AuditableEapEntity {
36→
37→    @Id
38→    @GeneratedValue(strategy = GenerationType.IDENTITY)
39→    @Column(name = "{PK_COLUMN}", nullable = false)
40→    public Integer {pkField};
41→
42→    @Column(name = "{COLUMN_NAME}", length = 100, nullable = false)
43→    public String {fieldName};
44→
45→    // ==================== Panache 查詢方法 ====================
46→
47→    public static {EntityName}Entity findByKey({PKType} {pkField}) {
48→        return find("{pkField}", {pkField}).firstResult();
49→    }
50→
51→    public static boolean existsByKey({PKType} {pkField}) {
52→        return count("{pkField}", {pkField}) > 0;
53→    }
54→
55→    public static List<{EntityName}Entity> findAllXxx(Map<String, Object> criteria) {
56→        StringBuilder query = new StringBuilder("FROM {EntityName}Entity e WHERE 1=1");
57→        List<Object> params = new ArrayList<>();
58→
59→        if (criteria.containsKey("fieldName") && criteria.get("fieldName") != null) {
60→            String val = criteria.get("fieldName").toString().trim();
61→            if (!val.isEmpty()) {
62→                query.append(" AND e.fieldName LIKE ?").append(params.size() + 1);
63→                params.add("%" + val + "%");
64→            }
65→        }
66→
67→        query.append(" ORDER BY e.{sortField}");
68→        PanacheQuery<{EntityName}Entity> panacheQuery = find(query.toString(), params.toArray());
69→        return panacheQuery.list();
70→    }
71→}
