  6→package org.soetek.eap.{moduleCode}.processor;
  7→
  8→import jakarta.enterprise.context.ApplicationScoped;
  9→import jakarta.enterprise.context.control.ActivateRequestContext;
 10→import jakarta.inject.Named;
 11→import lombok.extern.slf4j.Slf4j;
 12→import org.apache.camel.Body;
 13→import org.apache.camel.Exchange;
 14→import org.apache.camel.Headers;
 15→import org.soetek.eap.{moduleCode}.domain.{EntityName}Entity;
 16→import org.soetek.foundation.config.annotation.AuditLog;
 17→import org.soetek.foundation.processor.ApiRouteProcessor;
 18→import org.soetek.foundation.util.DateFormatUtil;
 19→import org.soetek.foundation.util.LogType;
 20→import org.soetek.foundation.util.PaginationUtil;
 21→import org.soetek.foundation.util.PaginationUtil.PaginationParams;
 22→import org.soetek.foundation.util.PaginationUtil.PaginationResult;
 23→
 24→import java.util.HashMap;
 25→import java.util.List;
 26→import java.util.Map;
 27→
 28→@Slf4j
 29→@ApplicationScoped
 30→@Named("{routeId}Processor")
 31→public class {EntityName}QueryProcessor extends ApiRouteProcessor {
 32→
 33→    @Override
 34→    public Map<String, Object> getTemplateParams() {
 35→        return Map.of(
 36→            "routeId", "{routeId}",
 37→            "apiDescription", "{查詢描述}",
 38→            "requiredFields", "");
 39→    }
 40→
 41→    @Override
 42→    protected String getProcessorType() {
 43→        return LogType.API_PROCESSING;
 44→    }
 45→
 46→    @Override
 47→    @ActivateRequestContext
 48→    @AuditLog(
 49→        operation = AuditLog.OperationType.QUERY,
 50→        entity = "{EntityName}",
 51→        description = "{查詢描述}",
 52→        logParameters = true,
 53→        logResult = true
 54→    )
 55→    public Object process(Exchange exchange, @Body Map<String, Object> payload,
 56→            @Headers Map<String, Object> headers) throws Exception {
 57→        return executeWithErrorHandling(exchange, payload, headers);
 58→    }
 59→
 60→    @Override
 61→    @SuppressWarnings("unchecked")
 62→    protected Object processBusinessLogic(
 63→            Exchange exchange, Map<String, Object> payload,
 64→            Map<String, Object> headers, String traceId, String routeId) throws Exception {
 65→
 66→        log.debug("[{模組} 查詢] 開始 - TraceId: {}, Payload: {}", traceId, payload);
 67→
 68→        // 1. 解析分頁參數
 69→        PaginationParams paginationParams = PaginationUtil.parsePaginationParams(payload);
 70→
 71→        // 2. 查詢資料
 72→        List<{EntityName}Entity> entityList = {EntityName}Entity.findAllXxx(payload);
 73→
 74→        log.debug("[{模組} 查詢] 查詢結果 - 總筆數: {}, TraceId: {}", entityList.size(), traceId);
 75→
 76→        // 3. 轉換為 Map
 77→        List<Map<String, Object>> recordList = entityList.stream()
 78→                .map(this::convertToMap)
 79→                .toList();
 80→
 81→        // 4. 分頁
 82→        PaginationResult<Map<String, Object>> result = PaginationUtil.paginate(recordList, paginationParams);
 83→
 84→        log.info("[{模組} 查詢] 成功 - TotalCount: {}, CurrentPage: {}, TraceId: {}",
 85→                result.getTotalCount(), result.getCurrentPage(), traceId);
 86→
 87→        // 5. 組裝回應（items → records rename）
 88→        Map<String, Object> response = new HashMap<>(result.toResponseMap("查詢成功"));
 89→        response.put("traceId", traceId);
 90→
 91→        Map<String, Object> existingData = (Map<String, Object>) response.get("data");
 92→        if (existingData != null && existingData.containsKey("items")) {
 93→            Map<String, Object> enhancedData = new HashMap<>(existingData);
 94→            enhancedData.put("records", enhancedData.remove("items"));
 95→            response.put("data", enhancedData);
 96→        }
 97→
 98→        return response;
 99→    }
100→
101→    private Map<String, Object> convertToMap({EntityName}Entity entity) {
102→        Map<String, Object> map = new HashMap<>();
103→        map.put("{pkField}", entity.{pkField});
104→        // map.put("fieldName", entity.fieldName);
105→        // ⭐ 日期格式化用 DateFormatUtil
106→        map.put("createDt", DateFormatUtil.formatDateTime(entity.createDt));
107→        map.put("updateDt", DateFormatUtil.formatDateTime(entity.updateDt));
108→        return map;
109→    }
110→}
111→```
112→
113→## 結構要點
114→
115→- **無 `@Transactional`** — Query 是唯讀操作
116→- **分頁**: `PaginationUtil.parsePaginationParams()` + `.paginate()` — 後端分頁
117→- **回應 key**: PaginationUtil 產出 `items`，手動 rename 為 `records`（前端慣例）。⚠️ 此為 Query 分頁場景的例外 — `PaginationUtil.toResponseMap()` 產出的結構需要手動調整，不適用 `buildStandardResponse()`
118→- **日期**: 使用 `DateFormatUtil.formatDateTime()` / `DateFormatUtil.formatDate()`
119→- **不回傳 entityId** — Query 不需要
120→
121→## 何時用 EntityManager 原生查詢
122→
123→- 多表 JOIN（如查詢時需要跨表取員工姓名）
124→- 聚合計算（SUM, COUNT, GROUP BY）
125→- 跨 Schema 查詢（HRM + EAP）
126→- **原生 SQL 必須加 Schema Prefix**（`EAP.TABLE` 或 `HRM.TABLE`）
127→
128→## ⚠️ 與現有代碼的差異
129→
130→AU010 CalendarQuery 不使用 PaginationUtil、回應 key 用 `items` 不 rename `records`、日期用 `.toString()` — 這是特殊場景（日曆按月查詢不需分頁）。**一般 Query 以本模板為準**。
