package org.soetek.eap.tm.domain;

import io.quarkus.runtime.annotations.RegisterForReflection;
import jakarta.persistence.*;
import lombok.AllArgsConstructor;
import lombok.Data;
import lombok.EqualsAndHashCode;
import lombok.NoArgsConstructor;
import org.hibernate.annotations.Cache;
import org.hibernate.annotations.CacheConcurrencyStrategy;
import org.soetek.eap.demo.domain.AuditableEapEntity;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.util.List;

/**
 * 員工年度假別額度 Entity
 * <p>
 * 對應 EAP.TM_EMP_VACATION 資料表
 * 記錄每位員工各假別的年度額度、已用時數、剩餘時數等資訊
 *
 * @author SoeTek Team
 * @since 2026-03-26
 */
@Data
@NoArgsConstructor
@AllArgsConstructor
@EqualsAndHashCode(callSuper = false)
@Entity
@Table(name = "TM_EMP_VACATION")
@RegisterForReflection
@Cacheable
@Cache(usage = CacheConcurrencyStrategy.READ_WRITE)
public class TmEmpVacationEntity extends AuditableEapEntity {

    // ==================== 主鍵 ====================

    /**
     * 流水號 (PK)
     */
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    @Column(name = "EMP_VACATION_ID", nullable = false)
    public Integer empVacationId;

    // ==================== 關聯欄位 ====================

    /**
     * 員工ID (FK to PM_EMPLOYEE)
     */
    @Column(name = "EMP_ID", nullable = false)
    public Integer empId;

    /**
     * 假別明細ID (FK to TM_VACATION_DETAIL_SETTING)
     */
    @Column(name = "VACATION_SUB_ID", nullable = false)
    public Integer vacationSubId;

    // ==================== 時數欄位 ====================

    /**
     * 可請時數 (8hr = 1日)
     */
    @Column(name = "MAX_HOURS", precision = 5, scale = 1)
    public BigDecimal maxHours;

    /**
     * 已請時數
     */
    @Column(name = "USED_HOURS", precision = 5, scale = 1)
    public BigDecimal usedHours;

    /**
     * 剩餘時數 (= MAX_HOURS - USED_HOURS)
     */
    @Column(name = "UNUSED_HOURS", precision = 5, scale = 1)
    public BigDecimal unusedHours;

    /**
     * 不休假轉工資時數
     */
    @Column(name = "CASH_OUT_HOURS", precision = 5, scale = 1)
    public BigDecimal cashOutHours;

    // ==================== 日期欄位 ====================

    /**
     * 額度生效起始日
     */
    @Column(name = "BEGIN_DATE", nullable = false)
    public LocalDate beginDate;

    /**
     * 額度生效結束日
     */
    @Column(name = "END_DATE", nullable = false)
    public LocalDate endDate;

    // ==================== 狀態欄位 ====================

    /**
     * 結算 (外部批次設定，本功能唯讀)
     */
    @Column(name = "CLEAR")
    public Boolean clear;

    // ==================== Panache 查詢方法 ====================

    /**
     * 根據主鍵查詢
     *
     * @param empVacationId 流水號
     * @return 員工假別額度
     */
    public static TmEmpVacationEntity findByKey(Integer empVacationId) {
        return find("empVacationId", empVacationId).firstResult();
    }

    /**
     * 檢查主鍵是否存在
     *
     * @param empVacationId 流水號
     * @return 是否存在
     */
    public static boolean existsByKey(Integer empVacationId) {
        return count("empVacationId", empVacationId) > 0;
    }

    /**
     * 根據員工ID和年度查詢假別額度清單
     *
     * @param empId 員工ID
     * @param year  年度
     * @return 假別額度列表
     */
    public static List<TmEmpVacationEntity> findByEmpIdAndYear(Integer empId, int year) {
        return find("empId = ?1 AND YEAR(beginDate) = ?2 ORDER BY vacationSubId",
                empId, year).list();
    }
}

package org.soetek.eap.tm.service;

import io.quarkus.hibernate.orm.PersistenceUnit;
import jakarta.enterprise.context.ApplicationScoped;
import jakarta.inject.Inject;
import jakarta.persistence.EntityManager;
import jakarta.persistence.Query;
import lombok.extern.slf4j.Slf4j;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

/**
 * TM 模組員工資訊查詢服務
 * <p>
 * 提供依員工編號查詢員工基本資訊的功能，
 * 供 TmEmpInfoQueryProcessor 和 TmUserOrgQueryProcessor 使用。
 *
 * @author SoeTek Team
 * @since 2026-03-17
 */
@Slf4j
@ApplicationScoped
public class TmEmployeeQueryService {

    @Inject
    @PersistenceUnit("eap")
    EntityManager em;

    /**
     * 依員工編號查詢員工基本資訊
     *
     * @param empAccount 員工編號
     * @return 員工資訊 Map，查無回傳 null
     */
    public Map<String, Object> getEmployeeByAccount(String empAccount) {
        String sql = """
                SELECT
                    e.EMP_ID        AS empId,
                    e.EMP_ACCOUNT   AS empAccount,
                    e.EMP_NAME      AS empName,
                    e.EMP_NAME_EN   AS empNameEn,
                    e.GENDER        AS gender,
                    e.ORG_ID        AS orgId,
                    org.ORG_NAME    AS orgName,
                    e.LEAVE_DATE    AS leaveDate
                FROM EAP.PM_EMPLOYEE e
                LEFT JOIN EAP.AU_ORGANIZATION org ON org.ORG_ID = e.ORG_ID
                WHERE e.EMP_ACCOUNT = :empAccount
                """;

        Query query = em.createNativeQuery(sql);
        query.setParameter("empAccount", empAccount);

        @SuppressWarnings("unchecked")
        List<Object[]> rows = query.getResultList();

        if (rows.isEmpty()) {
            return null;
        }

        Object[] row = rows.get(0);
        Map<String, Object> result = new HashMap<>();
        result.put("empId", row[0]);
        result.put("empAccount", row[1]);
        result.put("empName", row[2]);
        result.put("empNameEn", row[3]);
        result.put("gender", row[4]);
        result.put("orgId", row[5]);
        result.put("orgName", row[6]);
        result.put("leaveDate", row[7]);

        return result;
    }

    /**
     * 依登入帳號查詢使用者組織資訊
     *
     * @param empAccount 登入帳號
     * @return 使用者組織資訊 Map，查無回傳 null
     */
    public Map<String, Object> getUserOrgInfo(String empAccount) {
        // 同 getEmployeeByAccount 但可擴充更多組織資訊
        return getEmployeeByAccount(empAccount);
    }
}

