/**
 * TM002 員工假別明細查詢 Processor
 * <p>
 * 依員工ID+年度查詢假別明細
 * API 路徑：POST /api/tm002EmpVacationDetail
 *
 * @author SoeTek Team
 * @since 2026-03-26
 */
@Slf4j
@ApplicationScoped
@Named("tm002EmpVacationDetailProcessor")
@RegisterForReflection
public class Tm002EmpVacationDetailProcessor extends ApiRouteProcessor {

    @Inject
    Tm002EmpVacationService empVacationService;

    @Override
    public Map<String, Object> getTemplateParams() {
        return Map.of(
                "routeId", "tm002EmpVacationDetail",
                "apiDescription", "查詢員工假別明細",
                "requiredFields", "empId,year");
    }

    @Override
    protected String getProcessorType() {
        return LogType.API_PROCESSING;
    }

    @Override
    @ActivateRequestContext
    @AuditLog(
            operation = AuditLog.OperationType.QUERY,
            entity = "TmEmpVacation",
            description = "查詢員工假別明細",
            logParameters = true,
            logResult = true
    )
    public Object process(Exchange exchange, @Body Map<String, Object> payload,
                          @Headers Map<String, Object> headers) throws Exception {
        return executeWithErrorHandling(exchange, payload, headers);
    }

    @Override
    protected Object processBusinessLogic(
            Exchange exchange,
            Map<String, Object> payload,
            Map<String, Object> headers,
            String traceId,
            String routeId) throws Exception {

        Integer empId = getRequiredInteger(payload, "empId", "員工ID");
        Integer year = getRequiredInteger(payload, "year", "年度");

        log.debug("[TM002 明細查詢] empId: {}, year: {}, TraceId: {}", empId, year, traceId);

        List<Map<String, Object>> records = empVacationService.queryEmpVacationDetail(empId, year);

        log.info("[TM002 明細查詢] 完成 - 回傳 {} 筆, TraceId: {}", records.size(), traceId);

        Map<String, Object> data = new HashMap<>();
        data.put("records", records);

        Map<String, Object> response = new HashMap<>();
        response.put("success", true);
        response.put("message", "查詢成功");
        response.put("data", data);
        response.put("traceId", traceId);
        return response;
    }

    private Integer getRequiredInteger(Map<String, Object> data, String key, String fieldName) {
        Object value = data.get(key);
        if (value == null) {
            throw new BusinessException("REQUIRED_FIELD", 400, fieldName + " 為必填欄位");
        }
        if (value instanceof Number) {
            return ((Number) value).intValue();
        }
        try {
            return Integer.parseInt(value.toString().trim());
        } catch (NumberFormatException e) {
            throw new BusinessException("INVALID_FORMAT", 400, fieldName + " 格式錯誤，必須為整數");
        }
    }
}

