 * @since 2026-03-26
 */
@Slf4j
@ApplicationScoped
@Named("tm002EmpVacationSaveProcessor")
@RegisterForReflection
public class Tm002EmpVacationSaveProcessor extends ApiRouteProcessor {

    @Inject
    Tm002EmpVacationService empVacationService;

    @Override
    public Map<String, Object> getTemplateParams() {
        return Map.of(
                "routeId", "tm002EmpVacationSave",
                "apiDescription", "儲存員工假別明細",
                "requiredFields", "empId,details");
    }

    @Override
    protected String getProcessorType() {
        return LogType.API_PROCESSING;
    }

    @Override
    @ActivateRequestContext
    @AuditLog(
            operation = AuditLog.OperationType.CREATE,
            entity = "TmEmpVacation",
            description = "儲存員工假別明細",
            logParameters = true,
            logResult = true
    )
    public Object process(Exchange exchange, @Body Map<String, Object> payload,
                          @Headers Map<String, Object> headers) throws Exception {
        return executeWithErrorHandling(exchange, payload, headers);
    }

    @Override
    @SuppressWarnings("unchecked")
    protected Object processBusinessLogic(
            Exchange exchange,
            Map<String, Object> payload,
            Map<String, Object> headers,
            String traceId,
            String routeId) throws Exception {

        // 驗證必填欄位
        Object empIdObj = payload.get("empId");
        if (empIdObj == null) {
            throw new BusinessException("REQUIRED_FIELD", 400, "empId 為必填欄位");
        }
        Integer empId = ((Number) empIdObj).intValue();

        Object detailsObj = payload.get("details");
        if (detailsObj == null || !(detailsObj instanceof List) || ((List<?>) detailsObj).isEmpty()) {
            throw new BusinessException("REQUIRED_FIELD", 400, "details 為必填欄位");
        }
        List<Map<String, Object>> details = (List<Map<String, Object>>) detailsObj;

        log.debug("[TM002 儲存] empId: {}, details: {} 筆, TraceId: {}", empId, details.size(), traceId);

        List<Map<String, Object>> savedRecords = empVacationService.saveEmpVacationDetails(empId, details);

        log.info("[TM002 儲存] 完成 - 儲存 {} 筆, TraceId: {}", savedRecords.size(), traceId);

        Map<String, Object> data = new HashMap<>();
        data.put("records", savedRecords);
        data.put("entityId", empId);

        Map<String, Object> response = new HashMap<>();
        response.put("success", true);
        response.put("message", "儲存成功");
        response.put("data", data);
        response.put("traceId", traceId);
        return response;
    }
}

