/**
 * TM002 員工年度假別額度維護 - TypeScript 型別定義
 *
 * @author SoeTek Team
 * @since 2026-03-26
 */

// ==========================================
// Entity 介面
// ==========================================

/** 員工假別額度清單項目 */
export interface IEmpVacationListItem {
  /** 額度流水號 */
  quotaId: number
  /** 員工ID */
  empId: number
  /** 年度 */
  year: number
  /** 員工編號 */
  empNo: string
  /** 員工姓名（中文） */
  empNameCh: string
  /** 員工姓名（英文） */
  empNameEn?: string
  /** 部門代碼 */
  deptCode: number
  /** 部門名稱 */
  deptName: string
  /** 假別代碼 */
  vacationCode: string
  /** 假別名稱 */
  vacationName: string
  /** 假別細項代碼 */
  vacationSubCode: string
  /** 假別細項名稱 */
  vacationSubName: string
  /** 生效起始日 */
  effectiveStartDate: string
  /** 生效結束日 */
  effectiveEndDate: string
  /** 可請額度（時數） */
  totalHours: number
  /** 已用額度（時數） */
  usedHours: number
  /** 剩餘額度（時數） */
  remainingHours: number
  /** 結算狀態 */
  settlementStatus: string
  /** 不休假轉工資時數 */
  cashOutHours?: number
}

/** 員工假別明細項目 */
export interface IEmpVacationDetail {
  /** 額度流水號（新增時為 undefined） */
  empVacationId?: number
  /** 員工ID */
  empId: number
  /** 假別細項ID */
  vacationSubId: number
  /** 假別代碼 */
  vacationCode?: string
  /** 假別名稱 */
  vacationName?: string
  /** 假別細項代碼 */
  vacationSubCode?: string
  /** 假別細項名稱 */
  vacationSubName?: string
  /** 可請時數 */
  maxHours: number
  /** 已用時數 */
  usedHours: number
  /** 剩餘時數 */
  unusedHours: number
  /** 不休假轉工資時數 */
  cashOutHours?: number
  /** 生效起始日 */
  beginDate: string
  /** 生效結束日 */
  endDate: string
  /** 結算 */
  clear: boolean
  /** 結算狀態 */
  settlementStatus?: string
}

/** 執行預設回傳項目 */
export interface IDefaultVacationItem {
  /** 假別代碼 */
  vacationCode: string
  /** 假別名稱 */
  vacationName: string
  /** 假別細項代碼 */
  vacationSubCode: string
  /** 假別細項名稱 */
  vacationSubName: string
  /** 假別細項ID */
  vacationSubId: number
  /** 最小時數 */
  minHours: number
  /** 最大時數 */
  maxHours: number
}

/** 員工資訊 */
export interface IEmployeeInfo {
  /** 員工ID */
  empId: number
  /** 員工編號 */
  empAccount: string
  /** 員工姓名 */
  empName: string
  /** 員工英文姓名 */
  empNameEn?: string
  /** 性別 */
  gender?: string
  /** 部門ID */
  orgId?: number
  /** 部門名稱 */
  orgName?: string
  /** 離職日期 */
  leaveDate?: string
}

/** 批次驗證結果項目 */
export interface IBatchValidateResult {
  /** 員工編號 */
  empAccount: string
  /** 是否有效 */
  valid: boolean
  /** 錯誤訊息 */
  errorMessage?: string
  /** 員工ID */
  empId?: number
  /** 員工姓名 */
  empName?: string
  /** 部門ID */
  orgId?: number
  /** 部門名稱 */
  orgName?: string
}

// ==========================================
