/**
 * TM002 員工年度假別額度維護 - API 服務層
 *
 * @author SoeTek Team
 * @since 2026-03-26
 */

import { api } from 'boot/axios'
import type { ApiResponse } from 'src/types/common/api'
import type {
  IEmpVacationQueryParams,
  IEmpVacationQueryData,
  IEmpVacationDetailData,
  IDefaultVacationData,
  IEmpVacationSaveParams,
  IBatchValidateData,
  IBatchImportParams,
  IBatchImportData,
  IEmployeeInfo
} from 'src/types/tm/tm002'

// ==========================================
// API 端點常數
// ==========================================

const API_ENDPOINTS = {
  /** 清單查詢 */
  QUERY: '/empVacationQuery',
  /** 員工資訊查詢 */
  EMP_INFO: '/tmEmpInfoQuery',
  /** 執行預設（病假載入） */
  DEFAULT_VACATION: '/tm002DefaultVacation',
  /** 員工假別明細查詢 */
  DETAIL: '/tm002EmpVacationDetail',
  /** 員工假別明細儲存 */
  SAVE: '/tm002EmpVacationSave',
  /** 員工假別明細刪除 */
  DELETE: '/tm002EmpVacationDelete',
  /** 批次驗證 */
  BATCH_VALIDATE: '/tm002BatchValidate',
  /** 批次匯入 */
  BATCH_IMPORT: '/tm002BatchImport'
} as const

// ==========================================
// Service 實作
// ==========================================

export const tm002Service = {

  /**
   * 清單查詢
   */
  async query(params?: IEmpVacationQueryParams): Promise<ApiResponse<IEmpVacationQueryData>> {
    const response = await api.post<ApiResponse<IEmpVacationQueryData>>(
      API_ENDPOINTS.QUERY,
      params || {}
    )
    return response.data
  },

  /**
   * 員工資訊查詢
   */
  async queryEmpInfo(empAccount: string): Promise<ApiResponse<IEmployeeInfo>> {
    const response = await api.post<ApiResponse<IEmployeeInfo>>(
      API_ENDPOINTS.EMP_INFO,
      { empAccount }
    )
    return response.data
  },

  /**
   * 執行預設（病假載入）
   */
  async getDefaultVacation(year: number): Promise<ApiResponse<IDefaultVacationData>> {
    const response = await api.post<ApiResponse<IDefaultVacationData>>(
      API_ENDPOINTS.DEFAULT_VACATION,
      { year }
    )
    return response.data
  },

  /**
   * 員工假別明細查詢
   */
  async queryDetail(empId: number, year: number): Promise<ApiResponse<IEmpVacationDetailData>> {
    const response = await api.post<ApiResponse<IEmpVacationDetailData>>(
      API_ENDPOINTS.DETAIL,
      { empId, year }
    )
    return response.data
  },

  /**
   * 員工假別明細儲存
   */
  async save(params: IEmpVacationSaveParams): Promise<ApiResponse<IEmpVacationDetailData>> {
    const response = await api.post<ApiResponse<IEmpVacationDetailData>>(
      API_ENDPOINTS.SAVE,
      params
    )
    return response.data
  },

  /**
   * 員工假別明細刪除
   */
  async deleteDetail(empVacationId: number): Promise<ApiResponse<{ empVacationId: number }>> {
    const response = await api.post<ApiResponse<{ empVacationId: number }>>(
      API_ENDPOINTS.DELETE,
      { empVacationId }
    )
    return response.data
  },

  /**
   * 批次驗證員工
   */
  async batchValidate(empAccounts: string[]): Promise<ApiResponse<IBatchValidateData>> {
    const response = await api.post<ApiResponse<IBatchValidateData>>(
      API_ENDPOINTS.BATCH_VALIDATE,
      { empAccounts }
    )
    return response.data
  },

  /**
   * 批次匯入
   */
  async batchImport(params: IBatchImportParams): Promise<ApiResponse<IBatchImportData>> {
    const response = await api.post<ApiResponse<IBatchImportData>>(
      API_ENDPOINTS.BATCH_IMPORT,
      params
    )
    return response.data
  }
}

export default tm002Service

/**
 * TM002 員工年度假別額度維護 - Store
 *
 * @author SoeTek Team
 * @since 2026-03-26
 */

import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import { tm002Service } from 'src/services/tm/tm002Service'
import type {
  IEmpVacationListItem,
  IEmpVacationQueryParams,
  IEmpVacationDetail,
  IDefaultVacationItem,
  IEmployeeInfo,
  IBatchValidateResult,
  IEmpVacationSaveParams,
  IBatchImportParams
} from 'src/types/tm/tm002'

export const useTm002Store = defineStore('tm002', () => {

  // ==================== State ====================

  const records = ref<IEmpVacationListItem[]>([])
  const totalCount = ref(0)
  const currentPage = ref(1)
  const queryLoading = ref(false)
  const saveLoading = ref(false)
  const deleteLoading = ref(false)

  // Dialog state
  const detailRecords = ref<IEmpVacationDetail[]>([])
  const defaultVacationItems = ref<IDefaultVacationItem[]>([])
  const employeeInfo = ref<IEmployeeInfo | null>(null)
  const batchValidateResults = ref<IBatchValidateResult[]>([])

  // ==================== Getters ====================

  const hasData = computed(() => records.value.length > 0)
  const isAnyLoading = computed(() =>
    queryLoading.value || saveLoading.value || deleteLoading.value
  )

  // ==================== Actions ====================

  /** 清單查詢 */
  async function query(params?: IEmpVacationQueryParams): Promise<boolean> {
    queryLoading.value = true
    try {
      const response = await tm002Service.query(params)
      if (response.success && response.data) {
        records.value = response.data.records || []
        totalCount.value = response.data.totalCount || 0
        currentPage.value = response.data.currentPage || 1
        return true
      }
      return false
    } catch (err: unknown) {
      console.error('[TM002] 查詢失敗', err)
      return false
    } finally {
      queryLoading.value = false
    }
  }

  /** 員工資訊查詢 */
  async function queryEmpInfo(empAccount: string): Promise<IEmployeeInfo | null> {
    try {
      const response = await tm002Service.queryEmpInfo(empAccount)
      if (response.success && response.data) {
        employeeInfo.value = response.data
        return response.data
      }
      return null
    } catch (err: unknown) {
      console.error('[TM002] 員工查詢失敗', err)
      return null
    }
  }

  /** 執行預設（病假載入） */
  async function loadDefaultVacation(year: number): Promise<boolean> {
    try {
      const response = await tm002Service.getDefaultVacation(year)
      if (response.success && response.data) {
        defaultVacationItems.value = response.data.records || []
        return true
      }
      return false
    } catch (err: unknown) {
      console.error('[TM002] 執行預設失敗', err)
      return false
    }
  }

  /** 明細查詢 */
  async function queryDetail(empId: number, year: number): Promise<boolean> {
    queryLoading.value = true
    try {
      const response = await tm002Service.queryDetail(empId, year)
      if (response.success && response.data) {
        detailRecords.value = response.data.records || []
        return true
      }
      return false
    } catch (err: unknown) {
      console.error('[TM002] 明細查詢失敗', err)
      return false
    } finally {
      queryLoading.value = false
    }
  }

  /** 儲存明細 */
  async function saveDetails(params: IEmpVacationSaveParams): Promise<boolean> {
    saveLoading.value = true
    try {
      const response = await tm002Service.save(params)
      if (response.success) {
        return true
      }
      return false
    } catch (err: unknown) {
      console.error('[TM002] 儲存失敗', err)
      throw err
    } finally {
      saveLoading.value = false
    }
  }

  /** 刪除明細 */
  async function deleteDetail(empVacationId: number): Promise<boolean> {
    deleteLoading.value = true
    try {
      const response = await tm002Service.deleteDetail(empVacationId)
      if (response.success) {
        return true
      }
      return false
    } catch (err: unknown) {
      console.error('[TM002] 刪除失敗', err)
      throw err
    } finally {
      deleteLoading.value = false
    }
  }

  /** 批次驗證 */
  async function batchValidate(empAccounts: string[]): Promise<boolean> {
    try {
      const response = await tm002Service.batchValidate(empAccounts)
      if (response.success && response.data) {
        batchValidateResults.value = response.data.results || []
        return true
      }
      return false
    } catch (err: unknown) {
      console.error('[TM002] 批次驗證失敗', err)
      return false
    }
  }

  /** 批次匯入 */
  async function batchImport(params: IBatchImportParams): Promise<number> {
    saveLoading.value = true
    try {
      const response = await tm002Service.batchImport(params)
      if (response.success && response.data) {
        return response.data.createdCount
      }
      return 0
    } catch (err: unknown) {
      console.error('[TM002] 批次匯入失敗', err)
      throw err
    } finally {
      saveLoading.value = false
    }
  }

  /** 重置 */
  function $reset() {
    records.value = []
    totalCount.value = 0
    currentPage.value = 1
    queryLoading.value = false
    saveLoading.value = false
    deleteLoading.value = false
    detailRecords.value = []
    defaultVacationItems.value = []
    employeeInfo.value = null
    batchValidateResults.value = []
  }

  // ==================== Return ====================

  return {
    // State
    records, totalCount, currentPage,
    queryLoading, saveLoading, deleteLoading,
    detailRecords, defaultVacationItems, employeeInfo, batchValidateResults,
    // Getters
    hasData, isAnyLoading,
    // Actions
    query, queryEmpInfo, loadDefaultVacation, queryDetail,
    saveDetails, deleteDetail, batchValidate, batchImport, $reset
  }
})

